import java.util.concurrent.Executor;

public class LoginActivity extends AppCompatActivity {

    private static final String TAG = "LoginActivity";
    private static final String PREFS_NAME = "AppPrefs";
    private static final String BIOMETRIC_ENABLED_KEY = "biometric_login_enabled";

    private SharedPreferences sharedPreferences;
    private Switch enableBiometricSwitch;
    private Button biometricLoginButton; // For manual trigger, optional if auto-prompting
    private EditText usernameEditText, passwordEditText;
    private Button loginButton;

    private Executor executor;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);

        // Initialize UI elements
        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        loginButton = findViewById(R.id.loginButton);
        enableBiometricSwitch = findViewById(R.id.enableBiometricSwitch);
        biometricLoginButton = findViewById(R.id.biometricLoginButton);

        // Initialize executor and BiometricPrompt
        executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(LoginActivity.this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Log.e(TAG, "Authentication error: " + errString + " (Code: " + errorCode + ")");
                // Do not show toast for user cancellation or if device credential fallback is shown.
                // ERROR_LOCKOUT and ERROR_LOCKOUT_PERMANENT are usually handled by device credential.
                if (errorCode != BiometricPrompt.ERROR_USER_CANCELED &&
                    errorCode != BiometricPrompt.ERROR_NEGATIVE_BUTTON &&
                    errorCode != BiometricPrompt.ERROR_LOCKOUT &&
                    errorCode != BiometricPrompt.ERROR_LOCKOUT_PERMANENT) {
                    Toast.makeText(getApplicationContext(), "Authentication error: " + errString, Toast.LENGTH_SHORT).show();
                } else if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                    Toast.makeText(getApplicationContext(), "Authentication cancelled.", Toast.LENGTH_SHORT).show();
                }
            }

            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                Log.d(TAG, "Authentication succeeded!");
                Toast.makeText(getApplicationContext(), "Biometric Authentication Succeeded!", Toast.LENGTH_SHORT).show();
                navigateToMainActivity();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Log.w(TAG, "Authentication failed.");
                Toast.makeText(getApplicationContext(), "Biometric Authentication failed. Try again.", Toast.LENGTH_SHORT).show();
                // User stays on login screen. They can try again or use password.
            }
        });

        // Set initial state of the biometric switch
        enableBiometricSwitch.setChecked(sharedPreferences.getBoolean(BIOMETRIC_ENABLED_KEY, false));
        updateBiometricLoginButtonVisibility();

        // Listen for biometric switch changes
        enableBiometricSwitch.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (isChecked) {
                // User wants to enable biometric login
                checkBiometricCapabilityAndPromptForEnrollment(() -> {
                    // Only enable if biometrics are available and enrolled
                    sharedPreferences.edit().putBoolean(BIOMETRIC_ENABLED_KEY, true).apply();
                    Toast.makeText(LoginActivity.this, "Biometric login enabled.", Toast.LENGTH_SHORT).show();
                    updateBiometricLoginButtonVisibility();
                }, () -> {
                    // If not capable or enrolled, revert the switch
                    enableBiometricSwitch.setChecked(false);
                    sharedPreferences.edit().putBoolean(BIOMETRIC_ENABLED_KEY, false).apply();
                    updateBiometricLoginButtonVisibility();
                });
            } else {
                // User wants to disable biometric login
                sharedPreferences.edit().putBoolean(BIOMETRIC_ENABLED_KEY, false).apply();
                Toast.makeText(LoginActivity.this, "Biometric login disabled.", Toast.LENGTH_SHORT).show();
                updateBiometricLoginButtonVisibility();
            }
        });

        // Manual biometric login button click listener (shown if biometric is enabled)
        biometricLoginButton.setOnClickListener(v -> {
            if (sharedPreferences.getBoolean(BIOMETRIC_ENABLED_KEY, false)) {
                showBiometricPrompt();
            } else {
                Toast.makeText(this, "Biometric login is not enabled.", Toast.LENGTH_SHORT).show();
            }
        });

        // Standard password login button listener (simulated)
        loginButton.setOnClickListener(v -> {
            // In a real app, you'd validate username and password here
            String username = usernameEditText.getText().toString();
            String password = passwordEditText.getText().toString();

            if ("user".equals(username) && "pass".equals(password)) { // Dummy validation
                Toast.makeText(LoginActivity.this, "Password Login Succeeded (simulated)", Toast.LENGTH_SHORT).show();
                navigateToMainActivity();
            } else {
                Toast.makeText(LoginActivity.this, "Invalid credentials", Toast.LENGTH_SHORT).show();
            }
        });

        // Check if biometric login is enabled and try to authenticate automatically on app launch
        if (sharedPreferences.getBoolean(BIOMETRIC_ENABLED_KEY, false)) {
            Log.d(TAG, "Biometric login enabled, attempting auto-authentication.");
            showBiometricPrompt();
        }
    }

    /**
     * Controls the visibility of the manual biometric login button based on the biometric_login_enabled preference.
     */
    private void updateBiometricLoginButtonVisibility() {
        if (sharedPreferences.getBoolean(BIOMETRIC_ENABLED_KEY, false)) {
            biometricLoginButton.setVisibility(TextView.VISIBLE);
        } else {
            biometricLoginButton.setVisibility(TextView.GONE);
        }
    }

    /**
     * Checks the device's biometric capabilities and prompts the user to enroll if necessary.
     *
     * @param onSuccess Runnable to execute if biometrics are ready to be used.
     * @param onFailure Runnable to execute if biometrics are not available or enrolled.
     */
    private void checkBiometricCapabilityAndPromptForEnrollment(Runnable onSuccess, Runnable onFailure) {
        BiometricManager biometricManager = BiometricManager.from(this);
        String errorMessage;

        // Check for strong or weak biometrics
        int canAuthenticateResult = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);

        switch (canAuthenticateResult) {
            case BiometricManager.BIOMETRIC_SUCCESS:
                Log.d(TAG, "App can authenticate using biometrics.");
                onSuccess.run();
                return; // Exit as success
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                errorMessage = "No biometric hardware available on this device.";
                break;
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                errorMessage = "Biometric features are currently unavailable. Try again later.";
                break;
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                errorMessage = "No biometrics enrolled. Please enroll a fingerprint or face.";
                Log.e(TAG, errorMessage);
                // Prompt user to go to settings to enroll biometrics
                new android.app.AlertDialog.Builder(this)
                        .setTitle("Biometrics Not Enrolled")
                        .setMessage("You need to set up biometrics (fingerprint/face) in your device settings to enable this feature.")
                        .setPositiveButton("Go to Settings", (dialog, which) -> {
                            Intent enrollIntent = new Intent(Settings.ACTION_BIOMETRIC_ENROLL);
                            // Specify strong or weak biometrics for enrollment intent
                            enrollIntent.putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED, BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);
                            startActivity(enrollIntent);
                        })
                        .setNegativeButton("Cancel", (dialog, which) -> dialog.dismiss())
                        .show();
                onFailure.run(); // Call failure runnable
                return; // Exit after handling enrollment prompt
            case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED:
                errorMessage = "Biometric authentication requires a security update.";
                break;
            case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                errorMessage = "Biometric authentication is not supported on this device version.";
                break;
            default:
                errorMessage = "Unknown biometric error.";
                break;
        }

        Log.e(TAG, errorMessage);
        Toast.makeText(this, errorMessage, Toast.LENGTH_LONG).show();
        onFailure.run(); // Call failure runnable
    }

    /**
     * Displays the BiometricPrompt dialog for authentication.
     */
    private void showBiometricPrompt() {
        BiometricManager biometricManager = BiometricManager.from(this);
        // Allow strong biometrics OR device PIN/pattern/password as a fallback
        int allowedAuthenticators = BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.DEVICE_CREDENTIAL;

        if (biometricManager.canAuthenticate(allowedAuthenticators) == BiometricManager.BIOMETRIC_SUCCESS) {
            promptInfo = new BiometricPrompt.PromptInfo.Builder()
                    .setTitle("App Login")
                    .setSubtitle("Log in using your fingerprint or device credentials")
                    .setDescription("Place your finger on the sensor or use your screen lock to proceed.")
                    .setAllowedAuthenticators(allowedAuthenticators)
                    // If DEVICE_CREDENTIAL is NOT included, you would typically use setNegativeButtonText
                    // .setNegativeButtonText("Use password instead")
                    .build();

            biometricPrompt.authenticate(promptInfo);
        } else {
            String message = "";
            int errorCode = biometricManager.canAuthenticate(allowedAuthenticators);
            switch (errorCode) {
                case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                    message = "No biometric hardware available.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                    message = "Biometric hardware is unavailable.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                    message = "No biometrics enrolled. Please enroll biometrics in device settings.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED:
                    message = "Biometric authentication requires a security update.";
                    break;
                case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                    message = "Biometric authentication is not supported.";
                    break;
                default:
                    message = "Biometric authentication not possible (Error Code: " + errorCode + ").";
                    break;
            }
            Log.e(TAG, "Biometric authentication not available: " + message);
            Toast.makeText(this, message + "\nPlease use password login.", Toast.LENGTH_LONG).show();
            // If an unrecoverable error occurs, consider disabling the biometric login option
            // sharedPreferences.edit().putBoolean(BIOMETRIC_ENABLED_KEY, false).apply();
            // enableBiometricSwitch.setChecked(false);
            // updateBiometricLoginButtonVisibility();
        }
    }

    /**
     * Navigates to the main activity of the app and finishes the login activity.
     */
    private void navigateToMainActivity() {
        Intent intent = new Intent(LoginActivity.this, MainActivity.class);
        startActivity(intent);
        finish(); // Prevent going back to LoginActivity
    }
}

package com.example.biometricauth;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        TextView welcomeTextView = findViewById(R.id.welcomeTextView);
        welcomeTextView.setText("Welcome! You are logged in to the main app content.");
    }
}

